def _power_bi_column_to_nested(power_bi_column: PowerBIColumn) -> PowerBIColumnNested:
    """Convert flat PowerBIColumn to nested format."""
    attrs = PowerBIColumnAttributes()
    _populate_power_bi_column_attrs(attrs, power_bi_column)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        power_bi_column,
        _POWER_BI_COLUMN_REL_FIELDS,
        PowerBIColumnRelationshipAttributes,
    )
    return PowerBIColumnNested(
        guid=power_bi_column.guid,
        type_name=power_bi_column.type_name,
        status=power_bi_column.status,
        version=power_bi_column.version,
        create_time=power_bi_column.create_time,
        update_time=power_bi_column.update_time,
        created_by=power_bi_column.created_by,
        updated_by=power_bi_column.updated_by,
        classifications=power_bi_column.classifications,
        classification_names=power_bi_column.classification_names,
        meanings=power_bi_column.meanings,
        labels=power_bi_column.labels,
        business_attributes=power_bi_column.business_attributes,
        custom_attributes=power_bi_column.custom_attributes,
        pending_tasks=power_bi_column.pending_tasks,
        proxy=power_bi_column.proxy,
        is_incomplete=power_bi_column.is_incomplete,
        provenance_type=power_bi_column.provenance_type,
        home_id=power_bi_column.home_id,
        depth=power_bi_column.depth,
        immediate_upstream=power_bi_column.immediate_upstream,
        immediate_downstream=power_bi_column.immediate_downstream,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _power_bi_column_from_nested(nested: PowerBIColumnNested) -> PowerBIColumn:
    """Convert nested format to flat PowerBIColumn."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else PowerBIColumnAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _POWER_BI_COLUMN_REL_FIELDS,
        PowerBIColumnRelationshipAttributes,
    )
    return PowerBIColumn(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        depth=nested.depth,
        immediate_upstream=nested.immediate_upstream,
        immediate_downstream=nested.immediate_downstream,
        **_extract_power_bi_column_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _power_bi_column_to_nested_bytes(
    power_bi_column: PowerBIColumn, serde: Serde
) -> bytes:
    """Convert flat PowerBIColumn to nested JSON bytes."""
    return serde.encode(_power_bi_column_to_nested(power_bi_column))


def _power_bi_column_from_nested_bytes(data: bytes, serde: Serde) -> PowerBIColumn:
    """Convert nested JSON bytes to flat PowerBIColumn."""
    nested = serde.decode(data, PowerBIColumnNested)
    return _power_bi_column_from_nested(nested)


